// ==UserScript==
// @name         Boss-Helper Clean
// @version 1.5.0
// @description  自动投递、黑名单过滤、界面优化
// @match        https://www.zhipin.com/*
// @match        https://wj.qq.com/s2/27127732/ab0d/*
// @grant        GM_addStyle
